// File: MedicineTypesList.js
import React from "react";
import { Card, CardBody, Container, Row, Col, Button, Table } from "reactstrap";
import { useNavigate } from "react-router-dom";
import Header from "components/Headers/Header.js";

const MedicineTypesList = () => {
    const navigate = useNavigate();
    const medicineTypes = [
        { id: 1, code: "MT001", name: "Thuốc giảm đau" },
        { id: 2, code: "MT002", name: "Thuốc kháng sinh" },
    ];

    return (
        <>
            <Header />
            <Container fluid className="mt-4">
                <Row>
                    <Col>
                        <h3 className="text-dark">Danh Sách Loại Thuốc</h3>
                        <Button color="primary" onClick={() => navigate("/admin/medicine-types/add")}>Thêm Loại Thuốc</Button>
                    </Col>
                </Row>
                <Card className="mt-4">
                    <CardBody>
                        <Table striped>
                            <thead>
                                <tr>
                                    <th>#</th>
                                    <th>Mã Loại Thuốc</th>
                                    <th>Tên Loại Thuốc</th>
                                    <th>Hành động</th>
                                </tr>
                            </thead>
                            <tbody>
                                {medicineTypes.map((type, index) => (
                                    <tr key={type.id}>
                                        <td>{index + 1}</td>
                                        <td>{type.code}</td>
                                        <td>{type.name}</td>
                                        <td>
                                            <Button color="warning" size="sm" className="mr-2">Sửa</Button>
                                            <Button color="danger" size="sm">Xóa</Button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </Table>
                    </CardBody>
                </Card>
            </Container>
        </>
    );
};

export default MedicineTypesList;
